insert into bpg.requisito (instrumento_version_id, codigo, categoria_codigo, categoria, seccion, orden_global, orden_categoria, texto, np, peso) values
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-001', 'ORG', 'Organización de la Empresa', 'PLANIFICACIÓN DE LA EMPRESA', 1, 1, 'La empresa cuenta con misión, visión y objetivos.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-002', 'ORG', 'Organización de la Empresa', 'PLANIFICACIÓN DE LA EMPRESA', 2, 2, 'Los procesos claves1 son planificados para cumplir con los objetivos.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-003', 'ORG', 'Organización de la Empresa', 'PLANIFICACIÓN DE LA EMPRESA', 3, 3, 'La planificación de los procesos claves incluye aspectos productivos, económicos, patrimoniales, financieros, ambientales, sociales, organizacionales, legales e impositivos.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-004', 'ORG', 'Organización de la Empresa', 'PLANIFICACIÓN DE LA EMPRESA', 4, 4, 'La planificación incluye las etapas de diagnóstico y evaluación.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-005', 'ORG', 'Organización de la Empresa', 'PLANIFICACIÓN DE LA EMPRESA', 5, 5, 'La planificación incluye además, las etapas de formulación y selección de alternativas a implementar.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-006', 'ORG', 'Organización de la Empresa', 'PLANIFICACIÓN DE LA EMPRESA', 6, 6, 'Existen planes de contingencia frente a factores climáticos, económicos u otros.', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-007', 'ORG', 'Organización de la Empresa', 'PLANIFICACIÓN DE LA EMPRESA', 7, 7, 'Los planes incluyen las acciones a implementar y la evaluación de su impacto.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-008', 'ORG', 'Organización de la Empresa', 'PLANIFICACIÓN DE LA EMPRESA', 8, 8, 'La empresa cumple los requisitos exigidos por el mercado de destino.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-009', 'ORG', 'Organización de la Empresa', 'GESTIÓN: EJECUCIÓN DE LA PLANIFICACIÓN Y CONTROL', 9, 9, 'Los planes de ejecución describen los procesos, cuentan con un cronograma de acción y responsables asignados.', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-010', 'ORG', 'Organización de la Empresa', 'GESTIÓN: EJECUCIÓN DE LA PLANIFICACIÓN Y CONTROL', 10, 10, 'Durante la ejecución son registrados los datos para realizar el seguimiento, monitoreo parcial y control de los planes.', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-011', 'ORG', 'Organización de la Empresa', 'GESTIÓN: EJECUCIÓN DE LA PLANIFICACIÓN Y CONTROL', 11, 11, 'Existen canales de comunicación entre los actores involucrados en la dirección, gestión y operación de la empresa.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-012', 'ORG', 'Organización de la Empresa', 'RESULTADOS Y APRENDIZAJE', 12, 12, 'La información sobre la implementación del plan permite evaluar los resultados obtenidos en relación con los objetivos propuestos.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-013', 'ORG', 'Organización de la Empresa', 'RESULTADOS Y APRENDIZAJE', 13, 13, 'Los procesos de la empresa son revisados periódicamente.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-014', 'ORG', 'Organización de la Empresa', 'ROLES EN LA EMPRESA', 14, 14, 'Los roles están definidos y documentados (una persona puede asumir más de un rol).', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-015', 'ORG', 'Organización de la Empresa', 'DOCUMENTACIÓN', 15, 15, 'La información clave de los procesos es registrada.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-016', 'ORG', 'Organización de la Empresa', 'DOCUMENTACIÓN', 16, 16, 'La trazabilidad de la información está garantizada.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-017', 'ORG', 'Organización de la Empresa', 'DOCUMENTACIÓN', 17, 17, 'Los planes, protocolos y registros están disponibles, actualizados, completos y conservados en la unidad de producción.', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-018', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 18, 18, 'Los objetivos y valores de la empresa están definidos, comunicados e incorporados/reflejados en todos los procesos de trabajo,', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-019', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 19, 19, 'El compromiso sobre los valores y conducta son promovidos entre los asociados externos y proveedores de la empresa.', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-020', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 20, 20, 'Se promueve la transparencia de todos los procesos.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-021', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 21, 21, 'La empresa realiza acciones internas que demuestran su compromiso con las personas que trabajan en la misma y con su entorno.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-022', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 22, 22, 'Se garantiza la calidad de vida laboral de las personas involucradas en la empresa, el trabajo decente, la seguridad y la salud en el ámbito laboral.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-023', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 23, 23, 'Los derechos humanos en compromiso con el futuro de los niños, la diversidad y equidad son respetados.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-024', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 24, 24, 'Se impiden todas las formas de discriminación, así como el trabajo infantil en la empresa y su entorno.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-025', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 25, 25, 'Los derechos y obligaciones como ciudadanos son ejercidos y promovidos.', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-026', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 26, 26, 'Para la selección de un proveedor se tiene en cuenta los criterios de selección establecidos por la empresa,', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-027', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 27, 27, 'Cuando se dispone de proveedores locales, éstos se priorizan para promover el desarrollo de la zona.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-028', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 28, 28, 'La empresa cuenta con las reglas explícitas que permiten ordenar las relaciones con clientes y otros productores.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-029', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 29, 29, 'La empresa vela por la inocuidad de los productos que brinda al mercado.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-030', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 30, 30, 'El impacto de la empresa en la comunidad (entorno) es gestionado.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'ORG-031', 'ORG', 'Organización de la Empresa', 'RESPONSABILIDAD SOCIAL EMPRESARIAL (RSE)', 31, 31, 'Se identifican los impactos positivos para promoverlos y los negativos para evaluar mecanismos para minimizarlos.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-001', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 32, 1, 'Hay responsable/s para los asuntos relacionados con el bienestar, la seguridad y la salud de las personas.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-002', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 33, 2, 'El personal del establecimiento cuenta con una libreta sanitaria actualizada, de acuerdo con la normativa vigente.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-003', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 34, 3, 'Los trabajadores comunican a sus superiores cualquier enfermedad o herida que padecen.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-004', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 35, 4, 'El personal cuenta con ropa de trabajo, elementos y equipamiento de protección necesarios acorde al tipo de tarea que realice.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-005', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 36, 5, 'El personal utiliza la ropa de trabajo, elementos y equipamiento de protección provistos.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-006', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 37, 6, 'La ropa de trabajo y de protección cumple con la normativa vigente.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-007', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 38, 7, 'La ropa de trabajo y de protección es guardada separada de los productos fitosanitarios y veterinarios.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-008', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 39, 8, 'Los elementos de protección personal son conservados en condiciones adecuadas.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-009', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 40, 9, 'El personal cuenta con elementos de higiene personal durante la jornada laboral.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-010', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 41, 10, 'El personal involucrado en la manipulación de productos fitosanitarios, veterinarios o desinfectantes está entrenado para tal fin.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-011', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 42, 11, 'Las fichas de seguridad de los productos fitosanitarios, veterinarios y desinfectantes manipulados están disponibles.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-012', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 43, 12, 'Las especificaciones dadas en los productos fitosanitarios, veterinarios y desinfectantes manipulados son cumplidas.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-013', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 44, 13, 'La evaluación de riesgos contempla los aspectos de bienestar, seguridad y salud de las personas que se encuentran en forma', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-014', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 45, 14, 'Los planes de acción de bienestar, seguridad y salud de las personas están establecidos', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-015', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 46, 15, 'Los protocolos para cada situación de riesgo que lo requiera están documentados y disponibles.', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-016', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 47, 16, 'El establecimiento cuenta con señalización adecuada y de fácil comprensión sobre todos los riesgos de seguridad', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-017', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 48, 17, 'El establecimiento dispone de botiquines de primeros auxilios fijos y móviles, matafuegos', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-018', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 49, 18, 'Los protocolos a seguir en caso de accidentes son claros y están disponibles o visibles en los lugares identificados por la evaluación de riesgos.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-019', 'PER', 'Personal', 'BIENESTAR, SEGURIDAD Y SALUD DEL PERSONAL', 50, 19, 'La empresa cuenta con personas capacitadas en ejecutar los protocolos de accidentes y son periódicamente recapacitados y/o reentrenados.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-020', 'PER', 'Personal', 'REGISTRO Y RESPONSABILIDADES EN LA GESTIÓN DE LAS PERSONAS', 51, 20, 'El personal contratado, fijo o temporal, cuenta con la documentación que así lo demuestre.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-021', 'PER', 'Personal', 'REGISTRO Y RESPONSABILIDADES EN LA GESTIÓN DE LAS PERSONAS', 52, 21, 'Los registros del personal permanente y temporal se encuentran completos y actualizados.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-022', 'PER', 'Personal', 'REGISTRO Y RESPONSABILIDADES EN LA GESTIÓN DE LAS PERSONAS', 53, 22, 'En el organigrama y el manual de responsabilidades del personal se identifican las funciones y responsabilidades.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-023', 'PER', 'Personal', 'REGISTRO Y RESPONSABILIDADES EN LA GESTIÓN DE LAS PERSONAS', 54, 23, 'Dichos organigrama y manual se revisan periódicamente y están disponibles en un lugar visible con acceso a todo el personal.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-024', 'PER', 'Personal', 'REGISTRO Y RESPONSABILIDADES EN LA GESTIÓN DE LAS PERSONAS', 55, 24, 'Cuando se contratan servicios a terceros se corrobora que todo el personal interviniente tenga la cobertura de riesgo correspondiente', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-025', 'PER', 'Personal', 'GESTIÓN DEL PERSONAL', 56, 25, 'La política de gestión del personal que concilia los intereses de la organización con los de sus empleados está definida.', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-026', 'PER', 'Personal', 'GESTIÓN DEL PERSONAL', 57, 26, 'El plan para el desarrollo laboral del personal que trabaja en la empresa está alineado a los objetivos de la organización', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-027', 'PER', 'Personal', 'GESTIÓN DEL PERSONAL', 58, 27, 'Los mecanismos de comunicación entre los diferentes actores del establecimiento están establecidos.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-028', 'PER', 'Personal', 'GESTIÓN DEL PERSONAL', 59, 28, 'Las personas que trabajan en el establecimiento han sido comunicadas y comprenden sobre sus funciones y responsabilidades.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-029', 'PER', 'Personal', 'GESTIÓN DEL PERSONAL', 60, 29, 'Trabajar en la empresa permite un balance entre lo laboral y el desarrollo personal.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-030', 'PER', 'Personal', 'CAPACITACIÓN DEL PERSONAL', 61, 30, 'El personal tiene la competencia necesaria para el desarrollo de sus funciones y responsabilidades.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-031', 'PER', 'Personal', 'CAPACITACIÓN DEL PERSONAL', 62, 31, 'El plan de capacitación integral para el personal actual e ingresante según las funciones y responsabilidades asignadas está documentado e incluye formación en seguridad e higiene laboral, protección del ambiente y bienestar animal.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-032', 'PER', 'Personal', 'CAPACITACIÓN DEL PERSONAL', 63, 32, 'Los registros de las capacitaciones realizadas están disponibles.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'PER-033', 'PER', 'Personal', 'CAPACITACIÓN DEL PERSONAL', 64, 33, 'Periódicamente son evaluados los aprendizajes para programar las futuras capacitaciones o actividades de reentrenamiento.', 3, 2.5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'EST-001', 'EST', 'Establecimiento Ganadero', 'ESTABLECIMIENTO GANADERO', 65, 1, 'Tiene un mapa o croquis con la ubicación del establecimiento.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'EST-002', 'EST', 'Establecimiento Ganadero', 'ESTABLECIMIENTO GANADERO', 66, 2, 'En el mapa/croquis se detalla el apotreramiento, las instalaciones, los accesos, las fuentes hídricas, los ambientes, los suelos y demás características pertinentes.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'EST-003', 'EST', 'Establecimiento Ganadero', 'ESTABLECIMIENTO GANADERO', 67, 3, 'Tiene identificada la unidad de manejo de superficie1.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'INS-001', 'INS', 'Instalaciones, Equipos y Herramientas', 'INSTALACIONES, EQUIPOS Y HERRAM', 68, 1, 'Se dispone de un croquis que permita identificar las instalaciones disponibles y su distribución en el establecimiento.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'INS-002', 'INS', 'Instalaciones, Equipos y Herramientas', 'INSTALACIONES, EQUIPOS Y HERRAM', 69, 2, 'Las instalaciones están localizadas en zonas con drenaje y accesos adecuados.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'INS-003', 'INS', 'Instalaciones, Equipos y Herramientas', 'INSTALACIONES, EQUIPOS Y HERRAM', 70, 3, 'Los equipos y/o herramientas utilizados son adecuados a fin de evitar impactos negativos en el animal y/o el operador.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'INS-004', 'INS', 'Instalaciones, Equipos y Herramientas', 'INSTALACIONES, EQUIPOS Y HERRAM', 71, 4, 'Los equipos y/o herramientas se utilizan de acuerdo a las recomendaciones del fabricante.', 2, 5),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'INS-005', 'INS', 'Instalaciones, Equipos y Herramientas', 'HIGIENE Y MANTENIMIENTO', 72, 5, 'Tiene un plan de higiene (limpieza) y mantenimiento de las instalaciones, los equipos y las herramientas.', 1, 10),
  ('7d120107-0170-54e4-bcf6-88b4b4086564', 'INS-006', 'INS', 'Instalaciones, Equipos y Herramientas', 'HIGIENE Y MANTENIMIENTO', 73, 6, 'Estos planes incluyen objetivo, cronograma y protocolos.', 2, 5),
